function weightedIntervalMax(intervals) {
  if (!intervals || intervals.length === 0) return 0;

  const sorted = intervals.slice().sort((a, b) => a[1] - b[1]);
  const n = sorted.length;

  // dp[i] = max value using the first i intervals (sorted by end)
  const dp = new Array(n + 1).fill(0);

  for (let i = 1; i <= n; i++) {
    const [start, , value] = sorted[i - 1];

    // Find the last interval (by index in sorted order) that ends <= start.
    // Binary search over ends; touching (end === start) is compatible.
    let lo = 0, hi = i - 1, p = 0;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (sorted[mid][1] <= start) {
        p = mid + 1;
        lo = mid + 1;
      } else {
        hi = mid - 1;
      }
    }

    dp[i] = Math.max(dp[i - 1], dp[p] + value);
  }

  return dp[n];
}
